 1→import {
 2→  type ReactNode,
 3→  useCallback,
 4→  useEffect,
 5→  useId,
 6→  useRef,
 7→  useState,
 8→} from 'react';
 9→import './tooltip.scss';
10→
11→interface TooltipProps {
12→  content: string;
13→  children: ReactNode;
14→  delay?: number;
15→}
16→
17→export function Tooltip({ content, children, delay = 500 }: TooltipProps) {
18→  const [visible, setVisible] = useState(false);
19→  const [above, setAbove] = useState(false);
20→  const timerRef = useRef<ReturnType<typeof setTimeout>>(null);
21→  const triggerRef = useRef<HTMLSpanElement>(null);
22→  const tooltipId = useId();
23→
24→  const show = useCallback(() => {
25→    timerRef.current = setTimeout(() => {
26→      if (triggerRef.current) {
27→        const rect = triggerRef.current.getBoundingClientRect();
28→        const spaceBelow = window.innerHeight - rect.bottom;
29→        setAbove(spaceBelow < 60);
30→      }
31→      setVisible(true);
32→    }, delay);
33→  }, [delay]);
34→
35→  const hide = useCallback(() => {
36→    if (timerRef.current) {
37→      clearTimeout(timerRef.current);
38→      timerRef.current = null;
39→    }
40→    setVisible(false);
41→  }, []);
42→
43→  useEffect(() => {
44→    return () => {
45→      if (timerRef.current) {
46→        clearTimeout(timerRef.current);
47→      }
48→    };
49→  }, []);
50→
51→  return (
52→    <span
53→      ref={triggerRef}
54→      className="tooltip-trigger"
55→      onMouseEnter={show}
56→      onMouseLeave={hide}
57→      onFocus={show}
58→      onBlur={hide}
59→      aria-describedby={visible ? tooltipId : undefined}
60→    >
61→      {children}
62→      {visible && (
63→        <span
64→          id={tooltipId}
65→          role="tooltip"
66→          className={`tooltip${above ? ' tooltip--above' : ''}`}
67→        >
68→          {content}
69→        </span>
70→      )}
71→    </span>
72→  );
73→}
