 10→export interface ListItemProps {
 11→  index: number;
 12→  icon?: ReactNode;
 13→  title: string;
 14→  subtitle?: string;
 15→  accessories?: ListItemAccessoryData[];
 16→  onClick?: () => void;
 17→}
 18→
 19→function AccessoryWrapper({
 20→  tooltip,
 21→  children,
 22→}: {
 23→  tooltip?: string;
 24→  children: ReactNode;
 25→}) {
 26→  if (tooltip) {
 27→    return <Tooltip content={tooltip}>{children}</Tooltip>;
 28→  }
 29→  return <>{children}</>;
 30→}
 31→
 32→export function ListItem({
 33→  index,
 34→  icon,
 35→  title,
 36→  subtitle,
 37→  accessories,
 38→  onClick,
 39→}: ListItemProps) {
 40→  const { activeIndex, setActiveIndex } = useListContext();
 41→  const isActive = activeIndex === index;
 42→  const now = useMemo(() => new Date(), []);
 43→
 44→  const handleMouseEnter = useCallback(() => {
 45→    setActiveIndex(index);
 46→  }, [
 47→    index,
 48→    setActiveIndex,
 49→  ]);
 50→
 51→  return (
 52→    <div
 53→      id={`list-item-${index}`}
 54→      className={`list-item${isActive ? ' list-item--active' : ''}`}
 55→      data-list-index={index}
 56→      role="option"
 57→      aria-selected={isActive}
 58→      onMouseEnter={handleMouseEnter}
 59→      onClick={onClick}
 60→    >
 61→      <div className="list-item__left">
 62→        {icon && <span className="list-item__icon">{icon}</span>}
 63→        <span className="list-item__title">{title}</span>
 64→        {subtitle && <span className="list-item__subtitle">{subtitle}</span>}
 65→      </div>
 66→      {accessories && accessories.length > 0 && (
 67→        <div className="list-item__accessories">
 68→          {accessories.map((accessory, i) => {
 69→            const tooltipText =
 70→              accessory.tooltip ??
 71→              (accessory.date ? accessory.date.toLocaleString() : undefined);
 72→
 73→            if (accessory.tag) {
 74→              const hex = accessory.tag.color
 75→                ? TAG_COLOR_HEX[accessory.tag.color]
 76→                : undefined;
 77→              return (
 78→                <AccessoryWrapper key={i} tooltip={tooltipText}>
 79→                  <span
 80→                    className="list-item__accessory-tag"
 81→                    style={
 82→                      hex
 83→                        ? {
 84→                            color: hex,
 85→                            backgroundColor: `${hex}26`,
 86→                          }
 87→                        : undefined
 88→                    }
 89→                  >
 90→                    {accessory.tag.text}
 91→                  </span>
 92→                </AccessoryWrapper>
 93→              );
 94→            }
 95→            const displayText = accessory.date
 96→              ? formatRelativeDate(accessory.date, now)
 97→              : accessory.text;
 98→
 99→            return (
100→              <AccessoryWrapper key={i} tooltip={tooltipText}>
101→                <span className="list-item__accessory">
102→                  {accessory.icon}
103→                  {displayText && (
104→                    <span className="list-item__accessory-text">
105→                      {displayText}
106→                    </span>
107→                  )}
108→                </span>
109→              </AccessoryWrapper>
110→            );
111→          })}
112→        </div>
113→      )}
114→    </div>
115→  );
116→}
